for (Record r : records) {
events.add(new Event(r.startTime, 1));
events.add(new Event(r.endTime, -1));
}
events.sort((a, b) -> {
if (a.time != b.time) return Long.compare(a.time, b.time);
return Integer.compare(a.delta, b.delta); // 结束事件 -1 在前
